// Viability analysis for the incoming project
const { projectId, stageKey, executionId } = $input.first().json.body;

const sections = {
  marketAssessment: {
    score: Math.floor(Math.random() * 30) + 70,
    summary: "Market shows strong demand signals with growing TAM. Competitive landscape has gaps in automation and AI-driven workflows.",
    keyFindings: [
      "TAM growing at 15% CAGR",
      "3 direct competitors, none with full automation",
      "Customer pain points well-documented in industry reports"
    ]
  },
  technicalFeasibility: {
    score: Math.floor(Math.random() * 20) + 75,
    summary: "Core technology stack is proven. Integration points are well-documented. Main risk is in real-time data pipeline complexity.",
    keyFindings: [
      "API integrations available for all required services",
      "Real-time processing achievable with current infrastructure",
      "No novel algorithms required — proven patterns exist"
    ]
  },
  riskFactors: [
    { level: "medium", factor: "Market timing — early mover advantage window is 6-9 months" },
    { level: "low", factor: "Technical debt — greenfield build reduces legacy risk" },
    { level: "medium", factor: "Regulatory — data handling requirements vary by jurisdiction" }
  ],
  recommendation: {
    decision: "proceed",
    confidence: 0.85,
    summary: "Project shows strong viability across all dimensions. Recommend proceeding to architecture phase with focus on real-time pipeline design.",
    nextSteps: [
      "Define detailed technical architecture",
      "Identify key integration partners",
      "Establish data compliance framework"
    ]
  }
};

return {
  json: {
    projectId,
    stageKey,
    executionId,
    viabilityResult: sections
  }
};

// Post-approval handler
// The Wait node resumes when the bridge server calls the resumeUrl
const approvalData = $input.first().json;

console.log(`[lumon-n8n] Approval received for project=${approvalData.body?.projectId || 'unknown'}`);
console.log(`[lumon-n8n] Decision: approved — pipeline may now advance to next stage`);

return {
  json: {
    status: 'approval_received',
    message: 'Pipeline stage approved — ready for next stage execution',
    receivedAt: new Date().toISOString()
  }
};
